"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[591],{70186:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new Vetra instance and connects the per-frame simulation\\nloop to the appropriate RunService event (Heartbeat on server, RenderStepped\\non client).\\n\\n:::caution\\nCall this only once. Calling `new()` more than once will log a warning\\nand return an additional instance sharing the same underlying state \u2014\\nthe frame loop is not connected a second time.\\n:::","params":[],"returns":[{"desc":"","lua_type":"Vetra"}],"function_type":"static","source":{"line":59,"path":"docs/Vetra.lua"}},{"name":"Fire","desc":"Creates and registers a new in-flight projectile cast.\\n\\n`context` must have non-nil, finite `Origin` (Vector3), `Direction` (Vector3),\\nand `Speed` (number) fields. Any field omitted from `behavior` falls back to\\nthe built-in defaults.\\n\\nAfter `Fire` returns the cast is live and will be advanced every frame until\\nit hits something, expires by distance or speed, or is stopped via\\n`context:Terminate()`.","params":[{"name":"context","desc":"The public bullet object weapon code interacts with.","lua_type":"BulletContext"},{"name":"behavior","desc":"Optional behavior overrides. Omitted fields use defaults.","lua_type":"VetraBehavior?"}],"returns":[{"desc":"The internal cast object, or nil if validation failed.","lua_type":"VetraCast"}],"function_type":"method","source":{"line":76,"path":"docs/Vetra.lua"}},{"name":"GetSignals","desc":"Returns the module-level Signals table.\\n\\nConnect to these once during weapon initialisation. Every signal passes the\\n[BulletContext] as its first argument so you can identify the bullet and\\naccess its `UserData`.\\n\\n```lua\\nlocal Signals = Solver:GetSignals()\\n\\nSignals.OnHit:Connect(function(context, result, velocity)\\n    if result then\\n        -- physical surface impact\\n    else\\n        -- distance or speed expiry\\n    end\\nend)\\n\\nSignals.OnBounce:Connect(function(context, result, velocity, bounceCount)\\n    print(\\"Bounce #\\" .. bounceCount)\\nend)\\n```\\n\\n**Signal contracts:**\\n\\n| Signal | Arguments |\\n|--------|-----------|\\n| `OnHit` | `context`, `result: RaycastResult?`, `velocity: Vector3` |\\n| `OnTravel` | `context`, `position: Vector3`, `velocity: Vector3` |\\n| `OnPierce` | `context`, `result: RaycastResult`, `velocity: Vector3`, `pierceCount: number` |\\n| `OnBounce` | `context`, `result: RaycastResult`, `velocity: Vector3`, `bounceCount: number` |\\n| `OnTerminated` | `context` |\\n\\n`OnHit` fires with a nil `result` when the bullet expires by distance or minimum\\nspeed rather than a physical surface impact. Check `result ~= nil` to distinguish\\nthe two cases.\\n\\n`OnTravel` fires every frame using `Fire` (not `FireSafe`) \u2014 handlers must not throw.","params":[],"returns":[{"desc":"","lua_type":"{ OnHit: Signal, OnTravel: Signal, OnPierce: Signal, OnBounce: Signal, OnTerminated: Signal }"}],"function_type":"method","source":{"line":119,"path":"docs/Vetra.lua"}},{"name":"Destroy","desc":"Tears down this solver instance completely. After this call the instance\\nis inert \u2014 its frame loop is disconnected, all live casts are terminated,\\nall signals are destroyed, and all internal state is cleared.\\n\\n`OnTerminated` fires for every live cast during shutdown, giving consumers\\na final cleanup callback consistent with normal cast expiry.\\n\\n:::danger\\nCalling any method on the instance after `Destroy()` returns is undefined\\nbehaviour. The metatable is stripped and the table is frozen \u2014 all reads\\nand writes will error immediately at the call site.\\n:::\\n\\n:::caution\\n`Destroy()` is not safe to call twice. Guard against this with a flag on\\nyour own code if double-destruction is possible at your call sites.\\n:::","params":[],"returns":[],"function_type":"method","source":{"line":140,"path":"docs/Vetra.lua"}}],"properties":[{"name":"BehaviorBuilder","desc":"Re-export of the [BehaviorBuilder] module so consumers only need to require\\nVetra and can access the builder via `Vetra.BehaviorBuilder`.","lua_type":"BehaviorBuilder","source":{"line":45,"path":"docs/Vetra.lua"}}],"types":[],"name":"Vetra","desc":"Analytic-trajectory projectile simulation engine for Roblox.\\n\\nVetra manages all active in-flight projectiles. Every frame it advances\\neach cast using the exact kinematic formula `P(t) = Origin + V\u2080t + \xbdAt\xb2`,\\nraycasts between the previous and current position, and resolves hits as\\npierce, bounce, or terminal impact.\\n\\nSignals are module-level \u2014 connect once at initialisation and receive events\\nfrom every cast. The [BulletContext] argument on every signal lets you identify\\nwhich bullet fired the event and dispatch accordingly.\\n\\n```lua\\nlocal Vetra = require(path.to.Vetra)\\n\\nlocal Solver  = Vetra.new()\\nlocal Signals = Solver:GetSignals()\\n\\nSignals.OnHit:Connect(function(context, result, velocity)\\n    -- handle impact\\nend)\\n\\nlocal Behavior = Vetra.BehaviorBuilder.Sniper():Build()\\n\\nlocal context = BulletContext.new({\\n    Origin    = muzzlePosition,\\n    Direction = direction,\\n    Speed     = 300,\\n})\\n\\nSolver:Fire(context, Behavior)\\n```","source":{"line":36,"path":"docs/Vetra.lua"}}')}}]);